// Processa dados do pedido
const body = $input.first().json.body;

const nomeCliente   = body.clientName   || 'Cliente';
const telefone      = body.phone        || '';
const produto       = body.product      || 'Produto não especificado';
const quantidade    = parseInt(body.qty) || 1;
const valorUnit     = parseFloat(body.unitPrice) || 0;
const valorTotal    = (valorUnit * quantidade).toFixed(2);
const dataEntrega   = body.deliveryDate || 'A combinar';
const observacoes   = body.notes        || 'Nenhuma';
const formaPagto    = body.payment      || 'Pix';

const agora = new Date();
const numeroPedido = `PIT-${agora.getFullYear()}${String(agora.getMonth()+1).padStart(2,'0')}${String(agora.getDate()).padStart(2,'0')}-${Math.floor(Math.random()*900+100)}`;
const dataHora = agora.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

// Mensagem de confirmação para o cliente
const msgCliente = `🍬 *Pedido Confirmado — PiTa®*

Olá, *${nomeCliente}*! Seu pedido foi recebido com sucesso ✨

📋 *Nº do Pedido:* ${numeroPedido}
🎂 *Produto:* ${produto}
🔢 *Quantidade:* ${quantidade} un.
💰 *Valor total:* R$ ${valorTotal}
📅 *Entrega:* ${dataEntrega}
💳 *Pagamento:* ${formaPagto}

Embreve entraremos em contato para confirmar os detalhes!

_PiTa® — Qualidade · Criatividade · Paixão_`;

// Mensagem de alerta para equipe
const msgEquipe = `🔔 *NOVO PEDIDO PiTa®*

📋 *${numeroPedido}*
👤 Cliente: ${nomeCliente}
📞 Telefone: ${telefone}
🎂 Produto: ${produto} (${quantidade} un.)
💰 Total: R$ ${valorTotal}
📅 Entrega: ${dataEntrega}
📝 Obs: ${observacoes}
⏰ Recebido em: ${dataHora}`;

return [{ json: { numeroPedido, nomeCliente, telefone, produto, quantidade, valorTotal, dataEntrega, dataHora, msgCliente, msgEquipe } }];
